import React, { useState, useRef, useEffect } from "react";
import { Container, Button, Form, Card } from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";

function SpellingGame() {
  const [wordsIKindaKnow, setWordsIKindaKnow] = useState(["apple", "banana", "cat", "dog"]);
  const [wordsIDontKnow, setWordsIDontKnow] = useState(["andaconda", "table", "cable"]);
  const [levelWords, setLevelWords] = useState(["cane", "strawberry", "cage"]);
  const [wordsIKnow, setWordsIKnow] = useState([]);
  const [currentWord, setCurrentWord] = useState("");
  const [userInput, setUserInput] = useState("");
  const [message, setMessage] = useState("");
  const [incorrectAttempts, setIncorrectAttempts] = useState(0);
  const [gameLost, setGameLost] = useState(false);
  const [gameWon, setGameWon] = useState(false);

  const inputRef = useRef(null); // Create a reference for the input field

  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.focus(); // Automatically focus on the text field when the component loads
    }
  }, []);

  // Function to speak the word
  const speakWord = (word) => {
    if (word) {
      console.log("Speaking word:", word);
      const synth = window.speechSynthesis;
      const utterance = new SpeechSynthesisUtterance(word);
      utterance.lang = "en-ZA"; 
      utterance.rate = 0.9;
      utterance.pitch = 1.0;
      utterance.volume = 1.0;

      setTimeout(() => {
        synth.speak(utterance);
      }, 100);

      utterance.onstart = () => console.log("Speech started");
      utterance.onend = () => console.log("Speech ended");
    } else {
      console.log("No word to speak.");
    }
  };

  return (
    <Container className="text-center mt-5">
      <Card className="p-4">
        <h1>Spelling Game</h1>
        <Form.Control
          type="text"
          value={userInput}
          onChange={(e) => setUserInput(e.target.value)}
          className="mb-3"
          ref={inputRef} // Attach the ref to the input field
        />
      </Card>
    </Container>
  );
}

export default SpellingGame;
